import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import LoginPage from './pages/LoginPage';
import DashboardPage from './pages/DashboardPage';
import MISPage from './pages/MISPage';
import { ProtectedRoute } from './components/ProtectedRoute';
import './index.css';

function AppRoutes() {
  // ✅ ADDED loading + isAuthenticated (no removal)
  const { isAuthenticated, loading } = useAuth();

  // ✅ ADDED: prevent wrong redirect before auth loads
  if (loading) {
    return (
      <div style={{
        height: '100vh',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}>
        <h2>Loading...</h2>
      </div>
    );
  }

  return (
    <Routes>
      {/* ✅ NO CHANGE — just uses updated state */}
      <Route
        path="/"
        element={
          isAuthenticated
            ? <Navigate to="/dashboard" />
            : <LoginPage />
        }
      />

      {/* ✅ Protected dashboard */}
      <Route
        path="/dashboard"
        element={
          <ProtectedRoute>
            <DashboardPage />
          </ProtectedRoute>
        }
      />

      {/* ✅ Protected MIS */}
      <Route
        path="/mis"
        element={
          <ProtectedRoute>
            <MISPage />
          </ProtectedRoute>
        }
      />

      {/* ✅ OPTIONAL safety fallback (added, no removal) */}
      <Route path="*" element={<Navigate to="/" />} />
    </Routes>
  );
}

function App() {
  return (
    <Router>
      <AuthProvider>
        <AppRoutes />
      </AuthProvider>
    </Router>
  );
}

export default App;
